# Setup pins
relay = Pin(2, Pin.OUT)

# WebSocket handler
async def websocket_handler(reader, writer):
    try:
        data = await reader.read(1024)
        print('Received:', data)
        if b"GET / HTTP/1.1" in data:
            headers = "HTTP/1.1 101 Switching Protocols\r\n" \
                      "Upgrade: websocket\r\n" \
                      "Connection: Upgrade\r\n" \
                      "Sec-WebSocket-Accept: " \
                      + websocket_accept_key(data) + "\r\n\r\n"
            writer.write(headers.encode())

        while True:
            data = await reader.read(1024)
            if not data:
                break
            payload = parse_websocket_frame(data)
            if payload:
                await handle_command(payload)
    except Exception as e:
        print("Exception:", e)
    finally:
        await writer.aclose()

def websocket_accept_key(data):
    import ubinascii
    from hashlib import sha1
    key = [line for line in data.split(b"\r\n") if b'Sec-WebSocket-Key' in line][0]
    key = key.split(b": ")[1].strip()
    accept = sha1(key + b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11").digest()
    return ubinascii.b2a_base64(accept).decode().strip()

def parse_websocket_frame(data):
    length = data[1] & 127
    if length == 126:
        mask = data[4:8]
        start = 8
    elif length == 127:
        mask = data[10:14]
        start = 14
    else:
        mask = data[2:6]
        start = 6
    decoded = bytearray([data[i] ^ mask[i % 4] for i in range(start, len(data))])
    return bytes(decoded)

async def handle_command(payload):
    try:
        command = json.loads(payload)
        action = command.get("action")
        if action == "turn_on":
            relay.value(1)
            print("Relay turned on")
        elif action == "turn_off":
            relay.value(0)
            print("Relay turned off")
    except Exception as e:
        print("Error handling command:", e)

async def start_server():
    loop = asyncio.get_event_loop()
    server = await asyncio.start_server(websocket_handler, "0.0.0.0", 80)
    print("WebSocket server started")
    await server.wait_closed()

